import os
from pathlib import Path

def delete_uploaded_file(base_dir, filename):
    """
    Deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
    
    Args:
        base_dir (str): The path to the base directory where uploads are stored.
        filename (str): The name of the file to be deleted.

    Returns:
        bool: True if the file is successfully deleted, False otherwise.
    """
    
    # Canonicalize and validate file paths
    base_path = Path(base_dir).resolve()
    file_path = base_path / 'uploads' / filename
    
    # Ensure the resolved path stays within the intended base directory
    if not file_path.is_relative_to(base_path):
        raise ValueError("File path is outside of the base directory")
    
    try:
        os.remove(file_path)
        return True
    except FileNotFoundError:
        print(f"File {filename} does not exist.")
        return False
    except Exception as e:
        print(f"An error occurred: {e}")
        return False

# Example usage
